public class CastingExample {
    public static void main(String[] args) {
        // Implicit casting (Widening)
        int myInt = 9;
        double myDouble = myInt;

        // Explicit casting (Narrowing)
        double price = 9.78d;
        int roundedPrice = (int) price;

        System.out.println("Implicit: " + myInt + " -> " + myDouble);
        System.out.println("Explicit: " + price + " -> " + roundedPrice);
    }
}

import java.util.ArrayList;

public class WrapperExample {
    public static void main(String[] args) {
        ArrayList<Integer> numbers = new ArrayList<>();

        // Autoboxing: primitive 'int' to object 'Integer'
        numbers.add(10); 
        numbers.add(20);

        // Unboxing: object 'Integer' to primitive 'int'
        int sum = numbers.get(0) + numbers.get(1);

        System.out.println("Sum: " + sum);
    }
}

